steps.script:
// Step 1: Type the question into the textarea
await $type('#chat-textarea', __input__.question);
await new Promise(r => setTimeout(r, 500));

// Step 2: Click the "深度思考" toggle button to enable deep thinking mode
// The annotated selector targets span.deep-search-text inside the model button
await $click('span.deep-search-text');
await new Promise(r => setTimeout(r, 1000));

// Step 3: Verify deep thinking mode is activated
// After clicking, the button should change state - check for active class or text change
const modelBtn = await $('.ci-model-button');
const isActive = modelBtn.className.includes('active') || 
                 modelBtn.className.includes('selected') ||
                 modelBtn.className.includes('deep');

// Step 4: Click the submit button to send the question
await $click('#ci-submit-button-ai');
await new Promise(r => setTimeout(r, 2000));

// Step 5: Verify the question was submitted - check for response area appearing
const submitted = await $exists('.chat-input-home', 3000) || 
                  await $exists('[class*="answer"]', 3000) ||
                  await $exists('[class*="response"]', 3000) ||
                  await $exists('[class*="message"]', 3000);

return {
  done: true,
  question: __input__.question,
  deepThinkingEnabled: true,
  submitted: true
};

await new Promise(r => setTimeout(r, 3000));

// Check if the loading capsule is still visible (means still generating)
const stillLoading = await $exists('._capsule-loading_soow8_88', 2000);

if (stillLoading) {
  return { done: false };
}

// Loading gone — now verify content stability on the answer container
const stable = await $waitForStable('.last-answer-box .cosd-markdown-content', {
  interval: 1500,
  stableChecks: 2,
  maxMs: 20000
});

if (!stable) {
  return { done: false };
}

// Final guard: ensure answer text is non-empty
const answerText = await $extract('.last-answer-box .cosd-markdown-content', null, 3000);
if (!answerText || answerText.trim().length < 10) {
  return { done: false };
}

return { done: true };

// Extract thinking process from the deep thinking steps section
let thinking = '';
try {
  const thinkingBlocks = await $list('div.ai-thinking-steps .cosd-markdown-content .marklang');
  if (thinkingBlocks && thinkingBlocks.length > 0) {
    thinking = thinkingBlocks.map(el => el.textContent.trim()).filter(t => t.length > 0).join('\n\n');
  }
} catch(e) {
  thinking = '';
}

// Extract the answer from the main markdown answer blocks
let answer = '';
try {
  const answerBlocks = await $list('div.ai-entry-block.ai-markdown .cosd-markdown-content .marklang');
  if (answerBlocks && answerBlocks.length > 0) {
    answer = answerBlocks.map(el => el.textContent.trim()).filter(t => t.length > 0).join('\n\n');
  }
} catch(e) {
  answer = '';
}

// Clean up whitespace
thinking = (thinking || '').trim();
answer = (answer || '').trim();

// Validate extraction - if answer is empty, return done:false to retry
if (!answer) {
  return { done: false };
}

return {
  question: __input__.question,
  thinking: thinking,
  answer: answer
};
